// src/App.js
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

function App() {
  // Core node IDs
  const coreNodeIds = ["1", "2", "3", "4"];
  const randomTarget = coreNodeIds[Math.floor(Math.random() * coreNodeIds.length)];

  const handleDeleteNode = (targetId) => {
    setNodes((nds) => nds.filter((n) => n.id !== targetId));
    setEdges((eds) => eds.filter((e) => e.source !== targetId && e.target !== targetId));
  };

  const initialNodes = [
    { id: "1", type: "customInput", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llm", position: { x: 250, y: 50 }, data: {} },
    { id: "3", type: "text", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "customOutput", position: { x: 250, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 450, y: 125 }, // neatly beside the 4 nodes
      data: { targetId: randomTarget, onDelete: handleDeleteNode },
    },
  ];

  const initialEdges = [
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
    { id: "e5-" + randomTarget, source: "5", target: randomTarget }, // connect deleteNode to random target
  ];

  const [nodes, setNodes, onNodesChange] = useNodesState(initialNodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(initialEdges);

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={(params) => setEdges((eds) => [...eds, params])}
      />
    </div>
  );
}

export default App;
